 36→// Called when the game starts or when spawned
 37→void ALFPHexGridManager::BeginPlay()
 38→{
 39→	Super::BeginPlay();
 40→
 41→	// 如果有预设地图数据表，优先从数据表加载
 42→	if (MapDataTable)
 43→	{
