 52→// Called every frame
 53→void ALFPHexGridManager::Tick(float DeltaTime)
 54→{
 55→	Super::Tick(DeltaTime);
 56→
 57→	// 调试绘制网格
 58→	if (bDrawDebug)
 59→	{
 60→		for (auto& TilePair : GridMap)
 61→		{
 62→			if (TilePair.Value)
 63→			{
 64→				FVector Center = TilePair.Value->GetActorLocation();
 65→				DrawDebugHexagon(Center, FColor::Green);
 66→
 67→				// 显示坐标
 68→				FLFPHexCoordinates Coords = TilePair.Value->GetCoordinates();
 69→				FString CoordText = FString::Printf(TEXT("(%d,%d)"), Coords.Q, Coords.R);
 70→				DrawDebugString(GetWorld(), Center + FVector(0, 0, 20), CoordText, nullptr, FColor::White, 0, true);
 71→			}
 72→		}
