323→TArray<ALFPHexTile*> ALFPHexGridManager::GetSpawnPoints(ELFPSpawnFaction Faction) const
324→{
325→	TArray<ALFPHexTile*> Result;
326→	for (const auto& Pair : GridMap)
327→	{
328→		if (Pair.Value && Pair.Value->SpawnFaction == Faction && Pair.Value->SpawnIndex > 0)
329→		{
330→			Result.Add(Pair.Value);
331→		}
332→	}
333→	// 按 SpawnIndex 排序
334→	Result.Sort([](const ALFPHexTile& A, const ALFPHexTile& B)
335→	{
336→		return A.SpawnIndex < B.SpawnIndex;
337→	});
338→	return Result;
339→}
