695→FVector2D ALFPHexGridManager::WorldToHexGridPosition(const FVector& WorldPosition, float InHexSize, float InVerticalScale)
696→{
697→	// 尖顶六边形布局参数
698→	const float HorizontalSpacing = InHexSize * 1.5f * InVerticalScale; // 水平间距（应用垂直缩放）
699→	const float VerticalSpacing = InHexSize * FMath::Sqrt(3.0f); // 垂直间距
700→
701→	// 计算原点位置
702→	FVector GridOrigin = GetActorLocation();
703→
704→	// 计算相对于网格原点的位置
705→	float RelX = WorldPosition.X - GridOrigin.X;
706→	float RelY = WorldPosition.Y - GridOrigin.Y;
707→
708→	// 转换为六边形网格坐标（近似）
709→	return FVector2D(
710→		RelX / HorizontalSpacing,
711→		RelY / VerticalSpacing
712→	);
713→}
