 39→void ALFPTacticsPlayerController::BeginPlay()
 40→{
 41→    Super::BeginPlay();
 42→
 43→    // 设置输入模式
 44→    FInputModeGameAndUI InputMode;
 45→    InputMode.SetLockMouseToViewportBehavior(EMouseLockMode::DoNotLock);
 46→    InputMode.SetHideCursorDuringCapture(false);
 47→    SetInputMode(InputMode);
 48→    bShowMouseCursor = true;
 49→
 50→    // 获取网格管理器
 51→    TArray<AActor*> FoundActors;
 52→    UGameplayStatics::GetAllActorsOfClass(GetWorld(), ALFPHexGridManager::StaticClass(), FoundActors);
 53→    if (FoundActors.Num() > 0)
 54→    {
 55→        GridManager = Cast<ALFPHexGridManager>(FoundActors[0]);
 56→    }
 57→
 58→    // 设置Enhanced Input
 59→    if (UEnhancedInputLocalPlayerSubsystem* Subsystem = ULocalPlayer::GetSubsystem<UEnhancedInputLocalPlayerSubsystem>(GetLocalPlayer()))
 60→    {
 61→        if (DefaultInputMapping)
 62→        {
 63→            Subsystem->AddMappingContext(DefaultInputMapping, 0);
 64→        }
 65→    }
 66→
 67→    // 初始化UI
 68→    if (TurnSpeedWidgetClass)
 69→    {
 70→        TurnSpeedListWidget = CreateWidget<ULFPTurnSpeedListWidget>(this, TurnSpeedWidgetClass);
 71→        if (TurnSpeedListWidget)
 72→        {
 73→            TurnSpeedListWidget->AddToViewport();
 74→            TurnSpeedListWidget->InitializeTurnOrder(); // 初始化单位顺序
 75→        }
 76→    }
 77→
 78→    // 绑定阶段变化委托
 79→    if (ALFPTurnManager* TurnManager = GetTurnManager())
 80→    {
 81→        TurnManager->OnPhaseChanged.AddDynamic(this, &ALFPTacticsPlayerController::OnPhaseChanged);
 82→    }
 83→}
