647→bool ALFPTacticsPlayerController::AttackTarget(ALFPTacticsUnit* Attacker, ALFPTacticsUnit* Target)
648→{
649→    if (!Attacker || !Target || !Attacker->CanAct())
650→    {
651→        return false;
652→    }
653→
654→    // 计算攻击代价
655→    const int32 AttackCost = 1;
656→
657→    bIsAttacking = false;
658→    CurrentControlState = EPlayControlState::MoveState;
659→
660→    if (!Attacker->HasEnoughActionPoints(AttackCost))
661→    {
662→        return false;
663→    }
664→
665→    // 执行攻击逻辑
666→    bool bAttackSucceed = Attacker->AttackTarget(Target);
667→
668→    if (bAttackSucceed)
669→    {
670→		// 消耗行动力
671→		Attacker->ConsumeActionPoints(AttackCost);
672→        ShowUnitRange(EUnitRange::UR_Default);
673→    }
674→    else
675→    {
676→        ShowUnitRange(EUnitRange::UR_Move);
677→    }
678→
679→    // 通知回合管理器单位完成行动
680→    if (!Attacker->HasEnoughActionPoints(1))
681→    {
682→		if (bAttackSucceed)
683→		{
684→            SkipTurn(Attacker);
685→		}
686→    }
687→
688→    return bAttackSucceed;
689→}
