227→bool ALFPHexGridManager::SaveMapToCSV(const FString& CSVFilePath)
228→{
229→	// CSV 头部（UE DataTable 格式：第一列为 RowName）
230→	FString CSVContent = TEXT("---,Q,R,TerrainType,DecorationID,SpawnFaction,SpawnIndex,EventTag\n");
231→
232→	for (const auto& Pair : GridMap)
233→	{
234→		ALFPHexTile* Tile = Pair.Value;
235→		if (!Tile) continue;
236→
237→		FLFPHexCoordinates Coord = Tile->GetCoordinates();
238→		FString RowName = FString::Printf(TEXT("%d_%d"), Coord.Q, Coord.R);
239→
240→		// 地形类型枚举名
241→		ELFPTerrainType TType = Tile->GetTerrainData() ? Tile->GetTerrainData()->TerrainType : ELFPTerrainType::TT_Grass;
242→		FString TerrainStr = UEnum::GetValueAsString(TType);
243→		TerrainStr = TerrainStr.RightChop(TerrainStr.Find(TEXT("::")) + 2);
244→
245→		// 装饰 ID
246→		FString DecoStr = Tile->DecorationID.IsNone() ? TEXT("") : Tile->DecorationID.ToString();
247→
248→		// 出生点阵营
249→		FString SpawnStr = UEnum::GetValueAsString(Tile->SpawnFaction);
250→		SpawnStr = SpawnStr.RightChop(SpawnStr.Find(TEXT("::")) + 2);
251→
252→		// 事件标签
253→		FString EventStr = Tile->EventTag.IsValid() ? Tile->EventTag.ToString() : TEXT("");
254→
255→		CSVContent += FString::Printf(TEXT("%s,%d,%d,%s,%s,%s,%d,%s\n"),
256→			*RowName, Coord.Q, Coord.R, *TerrainStr, *DecoStr,
257→			*SpawnStr, Tile->SpawnIndex, *EventStr);
258→	}
259→
260→	// 确保目录存在
261→	FString Directory = FPaths::GetPath(CSVFilePath);
262→	if (!FPaths::DirectoryExists(Directory))
263→	{
264→		IFileManager::Get().MakeDirectory(*Directory, true);
265→	}
266→
267→	bool bSuccess = FFileHelper::SaveStringToFile(CSVContent, *CSVFilePath,
268→		FFileHelper::EEncodingOptions::ForceUTF8WithoutBOM);
269→
270→	if (bSuccess)
271→	{
272→		UE_LOG(LogTemp, Log, TEXT("SaveMapToCSV: 保存 %d 个格子到 %s"), GridMap.Num(), *CSVFilePath);
273→	}
274→	else
275→	{
276→		UE_LOG(LogTemp, Error, TEXT("SaveMapToCSV: 保存失败 %s"), *CSVFilePath);
277→	}
278→	return bSuccess;
279→}
