118→void ALFPTacticsPlayerController::Tick(float DeltaTime)
119→{
120→    Super::Tick(DeltaTime);
121→
122→    if (bIsDragging)
123→    {
124→        DragTime += DeltaTime;
125→    }
126→
127→    // 更新相机位置
128→    if (GridManager)
129→    {
130→        FVector CameraLocation = GridManager->GetActorLocation() + CameraOffset;
131→        FRotator CameraRotation(CameraRotationPitchAngle, CameraRotationYawAngle, 0);
132→        SetControlRotation(CameraRotation);
133→
134→        // 计算相机位置偏移
135→        FVector DirectionOffset = CameraRotation.Vector() * CurrentZoom;
136→        DirectionOffset.Z = CurrentZoom * 0.5f; // 高度由缩放比例决定
137→
138→        // 设置相机位置
139→        APawn* ControlledPawn = GetPawn();
140→        if (ControlledPawn)
141→        {
142→            FVector TargetLocation = CameraLocation + DirectionOffset;
143→            ControlledPawn->SetActorLocation(FMath::VInterpTo(
144→                ControlledPawn->GetActorLocation(),
145→                TargetLocation,
146→                DeltaTime,
147→                5.0f // 插值速度
148→            ));
149→        }
150→
151→        // 获取鼠标位置
152→        float MouseX, MouseY;
153→        if (GetMousePosition(MouseX, MouseY))
154→        {
155→            FVector2D ScreenPosition(MouseX, MouseY);
156→            // 获取光标下的六边形Tile
157→            ALFPHexTile* HoveredTile = GridManager->GetHexTileUnderCursor(ScreenPosition, this);
158→            // 处理鼠标悬停逻辑
159→            if (HoveredTile != LastHoveredTile)
160→            {
161→                if (LastHoveredTile)
162→                {
163→                    //LastHoveredTile->OnMouseExit();
164→                }
165→
166→                if (HoveredTile)
167→                {
168→                    SelectTile(HoveredTile);
169→                    //HoveredTile->OnMouseEnter();
170→                }
171→
172→                LastHoveredTile = HoveredTile;
173→            }
174→
175→            // 敌人计划预览：检测悬停的格子上是否有带行动计划的敌人
176→            if (CachedBattlePhase == EBattlePhase::BP_EnemyPlanning || CachedBattlePhase == EBattlePhase::BP_ActionPhase)
177→            {
178→                ALFPTacticsUnit* HoveredEnemy = nullptr;
179→                if (LastHoveredTile)
180→                {
181→                    ALFPTacticsUnit* UnitOnTile = LastHoveredTile->GetUnitOnTile();
182→                    if (UnitOnTile && UnitOnTile->IsEnemy() && UnitOnTile->HasActionPlan())
183→                    {
184→                        HoveredEnemy = UnitOnTile;
185→                    }
186→                }
187→
188→                if (HoveredEnemy && HoveredEnemy != PreviewedEnemy)
189→                {
190→                    HideEnemyPlanPreview();
191→                    ShowEnemyPlanPreview(HoveredEnemy);
192→                }
193→                else if (!HoveredEnemy && PreviewedEnemy)
194→                {
195→                    HideEnemyPlanPreview();
196→                }
197→            }
198→        }
199→    }
200→
201→    // 更新地图视觉效果
202→    if (LastControlState != CurrentControlState)
203→    {
204→        switch (CurrentControlState)
205→        {
206→        case EPlayControlState::MoveState:
207→            break;
208→        case EPlayControlState::SkillReleaseState:
209→            break;
210→        default:
211→            break;
212→        }
213→    }
214→}
