230→void ALFPTacticsPlayerController::OnSelectCompleted(const FInputActionValue& Value)
231→{
232→    if (!bIsSelecting) return;
233→    bIsSelecting = false;
234→
235→    // 获取鼠标位置
236→    float MouseX, MouseY;
237→    GetMousePosition(MouseX, MouseY);
238→    FVector2D SelectionEnd = FVector2D(MouseX, MouseY);
