250→            if (Unit)
251→            {
252→                SelectUnit(Unit);
253→                return;
254→            }
255→
256→            // 尝试选中格子
257→            ALFPHexTile* Tile = Cast<ALFPHexTile>(HitResult.GetActor());
258→            if (Tile)
259→            {
260→                SelectTile(Tile);
261→                return;
262→            }
263→        }
264→    }
