430→void ALFPTacticsPlayerController::OnCameraDragTriggered(const FInputActionValue& Value)
431→{
432→    if (!bIsDragging) return;
433→
434→    // 获取当前鼠标位置
435→    FVector2D CurrentMousePosition;
436→    GetMousePosition(CurrentMousePosition.X, CurrentMousePosition.Y);
437→
438→    // 计算鼠标移动偏移
439→    FVector2D MouseDelta = CurrentMousePosition - DragStartPosition;
440→
441→    // 反转Y轴（屏幕Y轴向下，世界Y轴向上）
442→    MouseDelta.Y = -MouseDelta.Y;
443→
444→    // 计算移动方向（基于当前相机旋转）
445→    FRotator CameraRotation(0, CameraRotationYawAngle, 0);
446→    FVector Right = CameraRotation.RotateVector(FVector::RightVector);
447→    FVector Forward = CameraRotation.RotateVector(FVector::ForwardVector);
448→
449→    // 计算移动偏移
450→    FVector PanDirection = (Right * -MouseDelta.X) + (Forward * -MouseDelta.Y);
451→    //PanDirection.Normalize();
452→
453→    // 应用移动
454→    CameraOffset += PanDirection * CameraDragSpeed;
455→
456→    // 更新起始位置为当前位置
457→    DragStartPosition = CurrentMousePosition;
458→}
