489→void ALFPTacticsPlayerController::SelectTile(ALFPHexTile* Tile)
490→{
491→    if (!SelectedUnit || !GridManager) return;
492→
493→    switch (CurrentControlState)
494→    {
495→    case EPlayControlState::MoveState:
496→        // 检查是否在可移动范围内
497→        if (MovementRangeTiles.Contains(Tile))
498→        {
499→            SelectedTile = Tile;
500→            ShowPathToSelectedTile();
501→        }
502→        else
503→        {
504→            SelectedTile = Tile;
505→            // 清除之前高亮显示的路径
506→            HidePathToRange();
507→        }
508→        break;
509→    case EPlayControlState::SkillReleaseState:
510→        SelectedTile = Tile;
511→        break;
512→    default:
513→        break;
514→    }
515→}
