341→TArray<ALFPHexTile*> ALFPHexGridManager::GetNeighbors(const FLFPHexCoordinates& Coords) const
342→{
343→	TArray<ALFPHexTile*> Neighbors;
344→
345→	for (const FLFPHexCoordinates& Dir : HexDirections)
346→	{
347→		FLFPHexCoordinates NeighborCoords(Coords.Q + Dir.Q, Coords.R + Dir.R);
348→		FIntPoint Key(NeighborCoords.Q, NeighborCoords.R);
349→
350→		if (ALFPHexTile* const* FoundTile = GridMap.Find(Key))
351→		{
352→			Neighbors.Add(*FoundTile);
353→		}
354→	}
355→
356→	return Neighbors;
357→}
