730→// 判断点是否在六边形内
731→bool ALFPHexGridManager::IsPointInHexagon(const FVector2D& Point, const FVector2D& Center, float InHexSize)
732→{
733→	// 坐标转换为相对于六边形中心的单位向量
734→	FVector2D relPoint = Point - Center;
735→
736→	// 尖顶六边形的顶点位置（从0度开始）
737→	static const TArray<FVector2D> vertices = [] {
738→		TArray<FVector2D> result;
739→		for (int i = 0; i < 6; i++) {
740→			float angle_deg = 60 * i; // 尖顶六边形从0度开始
741→			float angle_rad = FMath::DegreesToRadians(angle_deg);
742→			result.Add(FVector2D(FMath::Cos(angle_rad), FMath::Sin(angle_rad)));
743→		}
744→		return result;
745→		}();
746→
747→	// 判断点是否在六边形内（使用射线法）
748→	int crossings = 0;
749→	for (int i = 0; i < 6; i++) {
750→		int j = (i + 1) % 6;
751→		FVector2D v1 = vertices[i] * InHexSize;
752→		FVector2D v2 = vertices[j] * InHexSize;
753→
754→		// 检测边是否跨越y坐标
755→		if ((v1.Y > relPoint.Y) != (v2.Y > relPoint.Y)) {
756→			// 计算交点x坐标
757→			float intersectX = (v2.X - v1.X) * (relPoint.Y - v1.Y) / (v2.Y - v1.Y) + v1.X;
758→
759→			// 如果交点在点的右侧
760→			if (relPoint.X < intersectX) {
761→				crossings++;
762→			}
763→		}
764→	}
765→
766→	// 奇数次跨越表示在内部
767→	return (crossings % 2 == 1);
768→}
