835→// 优化后的四舍五入到最近六边形坐标
836→FLFPHexCoordinates ALFPHexGridManager::RoundToHex(float q, float r)
837→{
838→	// 转换为立方坐标
839→	float cube_x = q;
840→	float cube_z = r;
841→	float cube_y = -cube_x - cube_z;
842→
843→	// 分别四舍五入到最近整数
844→	int32 rx = FMath::RoundToInt(cube_x);
845→	int32 ry = FMath::RoundToInt(cube_y);
846→	int32 rz = FMath::RoundToInt(cube_z);
847→
848→	// 计算四舍五入误差
849→	float x_diff = FMath::Abs(rx - cube_x);
850→	float y_diff = FMath::Abs(ry - cube_y);
851→	float z_diff = FMath::Abs(rz - cube_z);
852→
853→	// 修正最大误差的分量
854→	if (x_diff > y_diff && x_diff > z_diff) {
855→		rx = -ry - rz;
856→	}
857→	else if (y_diff > z_diff) {
858→		ry = -rx - rz;
859→	}
860→	else {
861→		rz = -rx - ry;
862→	}
863→
864→	return FLFPHexCoordinates(rx, rz);
865→}
