277→void ALFPTacticsPlayerController::OnConfirmAction(const FInputActionValue& Value)
278→{
279→    bIsDragging = false;
280→    if (DragTime > DragThresholdTime)
281→    {
282→        DragTime = 0.f;
283→        return;
284→    }
285→    DragTime = 0.f;
286→
287→    // 编辑器模式优先处理
288→    if (MapEditorComponent && MapEditorComponent->IsEditorActive())
289→    {
290→        if (LastHoveredTile)
291→        {
292→            MapEditorComponent->ApplyToolToTile(LastHoveredTile);
293→        }
294→        else if (GridManager && MapEditorComponent->GetCurrentTool() == ELFPMapEditorTool::MET_AddTile)
295→        {
296→            // 对空白区域添加格子：射线投射到 Z=0 平面计算坐标
297→            FVector WorldOrigin, WorldDirection;
298→            DeprojectMousePositionToWorld(WorldOrigin, WorldDirection);
299→            if (FMath::Abs(WorldDirection.Z) > KINDA_SMALL_NUMBER)
300→            {
301→                float T = -WorldOrigin.Z / WorldDirection.Z;
302→                FVector HitPoint = WorldOrigin + WorldDirection * T;
303→                FVector2D LocalLoc(
304→                    HitPoint.X - GridManager->GetActorLocation().X,
305→                    HitPoint.Y - GridManager->GetActorLocation().Y
306→                );
307→                FLFPHexCoordinates Coord = FLFPHexCoordinates::FromWorldLocation(
308→                    LocalLoc, GridManager->GetHexSize(), GridManager->GetVerticalScale());
309→                MapEditorComponent->ApplyToolToCoord(Coord.Q, Coord.R);
310→            }
311→        }
312→        return;
313→    }
314→
315→    if (SelectedUnit && SelectedTile)
316→    {
317→        if (bIsAttacking)
318→        {
319→            // 获取鼠标位置
320→            float MouseX, MouseY;
321→            GetMousePosition(MouseX, MouseY);
322→            FVector2D SelectionEnd = FVector2D(MouseX, MouseY);
323→
324→            FHitResult HitResult;
325→            GetHitResultAtScreenPosition(SelectionEnd, ECC_Visibility, false, HitResult);
326→
327→            if (HitResult.bBlockingHit)
328→            {
329→                // 尝试选中单位
330→                ALFPTacticsUnit* Unit = Cast<ALFPTacticsUnit>(HitResult.GetActor());
331→                if (Unit)
332→                {
333→                    AttackTarget(SelectedUnit, Unit);
334→                    return;
335→                }
336→            }
337→        }
338→        else if (bIsReleaseSkill && CurrentSelectedSkill)
339→        {
340→            ExecuteSkill(CurrentSelectedSkill);
341→        }
342→        else
343→        {
344→            ConfirmMove();
345→        }
346→    }
347→    else if (SelectedUnit)
348→    {
349→        // 如果没有选中目标格子，显示可移动范围
350→        //ShowMovementRange(true);
351→    }
352→}
