	ELFPWorldMapEditorTool CurrentTool = ELFPWorldMapEditorTool::WMET_None;

	// 笔刷参数
	UPROPERTY(EditAnywhere, BlueprintReadWrite, Category = "Brush")
	ELFPWorldNodeType BrushNodeType = ELFPWorldNodeType::WNT_Battle;

	UPROPERTY(EditAnywhere, BlueprintReadWrite, Category = "Brush")
