	// 是否正在编辑内层战斗地图
	UPROPERTY(VisibleAnywhere, BlueprintReadOnly)
	bool bIsEditingBattleMap = false;

	// 缓存
	UPROPERTY()
	mutable TObjectPtr<ALFPWorldMapManager> CachedWorldMapManager;
};

