	UPROPERTY(EditAnywhere, BlueprintReadWrite, Category = "Brush")
	FString BrushBattleMapName;

	UPROPERTY(EditAnywhere, BlueprintReadWrite, Category = "Brush")
	FString BrushEventID;

	UPROPERTY(EditAnywhere, BlueprintReadWrite, Category = "Brush")
	int32 BrushEdgeTurnCost = 1;

