    // 计算移动代价
    const int32 MoveCost = 1;

    // 执行移动
    Unit->MoveToTile(TargetTile);

    // 通知回合管理器单位完成行动
    /*if (ALFPTurnManager* TurnManager = GetTurnManager())
    {
        TurnManager->OnUnitFinishedAction(Unit);
