// ==== 敌人计划预览和阶段感知 ====

void ALFPTacticsPlayerController::ShowEnemyPlanPreview(ALFPTacticsUnit* EnemyUnit)
{
    if (!EnemyUnit || !EnemyUnit->HasActionPlan()) return;

    PreviewedEnemy = EnemyUnit;
    const FEnemyActionPlan& Plan = EnemyUnit->CurrentActionPlan;

    // 高亮技能效果范围格子
    PreviewEffectTiles = Plan.EffectAreaTiles;
    for (ALFPHexTile* Tile : PreviewEffectTiles)
    {
        if (Tile)
        {
            Tile->SetRangeSprite(EUnitRange::UR_SkillEffect);
        }
    }
}

void ALFPTacticsPlayerController::HideEnemyPlanPreview()
{
    // 恢复预览格子为默认状态
    for (ALFPHexTile* Tile : PreviewEffectTiles)
    {
        if (Tile)
        {
            Tile->SetRangeSprite(EUnitRange::UR_Default);
        }
    }
    PreviewEffectTiles.Empty();
    PreviewedEnemy = nullptr;
}

void ALFPTacticsPlayerController::OnPhaseChanged(EBattlePhase NewPhase)
{
    CachedBattlePhase = NewPhase;

    // 阶段切换时清理预览状态
    HideEnemyPlanPreview();

    switch (NewPhase)
    {
    case EBattlePhase::BP_EnemyPlanning:
        // 敌人规划阶段：隐藏技能选择UI
        HideSkillSelection();
        break;

    case EBattlePhase::BP_ActionPhase:
        // 行动阶段：恢复正常
        break;

    case EBattlePhase::BP_RoundEnd:
        break;
    }
}

void ALFPTacticsPlayerController::OnToggleEditorAction(const FInputActionValue& Value)
{
    if (!MapEditorComponent) return;

    MapEditorComponent->ToggleEditorMode();

    if (MapEditorComponent->IsEditorActive())
    {
        // 创建或显示编辑器 Widget
        if (!MapEditorWidget && MapEditorWidgetClass)
        {
            MapEditorWidget = CreateWidget<ULFPMapEditorWidget>(this, MapEditorWidgetClass);
            if (MapEditorWidget)
            {
                MapEditorWidget->AddToViewport();
                MapEditorWidget->InitializeEditor(MapEditorComponent);
            }
        }
        else if (MapEditorWidget)
        {
            MapEditorWidget->SetVisibility(ESlateVisibility::Visible);
        }

        // 显示鼠标光标
        bShowMouseCursor = true;
    }
    else
    {
        // 隐藏编辑器 Widget
        if (MapEditorWidget)
        {
            MapEditorWidget->SetVisibility(ESlateVisibility::Collapsed);
        }
    }
}

void ALFPTacticsPlayerController::OnToggleWorldMapEditorAction(const FInputActionValue& Value)
{
    if (!WorldMapEditorComponent) return;

    WorldMapEditorComponent->ToggleEditorMode();

    if (WorldMapEditorComponent->IsEditorActive())
    {
        // 创建或显示编辑器 Widget
        if (!WorldMapEditorWidget && WorldMapEditorWidgetClass)
        {
            WorldMapEditorWidget = CreateWidget<ULFPWorldMapEditorWidget>(this, WorldMapEditorWidgetClass);
            if (WorldMapEditorWidget)
            {
                WorldMapEditorWidget->AddToViewport();
                WorldMapEditorWidget->InitializeEditor(WorldMapEditorComponent);
            }
        }
        else if (WorldMapEditorWidget)
        {
            WorldMapEditorWidget->SetVisibility(ESlateVisibility::Visible);
        }

        // 显示鼠标光标
        bShowMouseCursor = true;
    }
    else
    {
        // 隐藏编辑器 Widget
        if (WorldMapEditorWidget)
        {
            WorldMapEditorWidget->SetVisibility(ESlateVisibility::Collapsed);
        }
    }
}

