 21→// ============== 节点管理 ==============
 22→
 23→ALFPWorldMapNode* ALFPWorldMapManager::SpawnNode(int32 NodeID, FVector2D Position, ELFPWorldNodeType NodeType)
 24→{
 25→	// 检查 ID 冲突
 26→	if (NodeMap.Contains(NodeID))
 27→	{
 28→		UE_LOG(LogTemp, Warning, TEXT("SpawnNode: 节点 ID %d 已存在"), NodeID);
 29→		return NodeMap[NodeID];
 30→	}
 31→
 32→	if (!NodeActorClass)
 33→	{
 34→		UE_LOG(LogTemp, Error, TEXT("SpawnNode: NodeActorClass 未配置"));
 35→		return nullptr;
 36→	}
 37→
 38→	FVector SpawnLocation(Position.X, Position.Y, 0.f);
 39→	FActorSpawnParameters SpawnParams;
 40→	SpawnParams.Owner = this;
 41→
 42→	ALFPWorldMapNode* NewNode = GetWorld()->SpawnActor<ALFPWorldMapNode>(
 43→		NodeActorClass, SpawnLocation, FRotator::ZeroRotator, SpawnParams);
 44→
 45→	if (!NewNode) return nullptr;
 46→
 47→	NewNode->NodeID = NodeID;
 48→	NewNode->NodeType = NodeType;
 49→	NewNode->AttachToActor(this, FAttachmentTransformRules::KeepWorldTransform);
 50→
 51→	// 应用视觉数据
 52→	if (ULFPWorldNodeDataAsset* VisualData = GetNodeVisualForType(NodeType))
 53→	{
 54→		NewNode->SetNodeVisualData(VisualData);
 55→	}
 56→
 57→	NodeMap.Add(NodeID, NewNode);
 58→
 59→	// 确保邻接表有条目
 60→	if (!AdjacencyList.Contains(NodeID))
 61→	{
 62→		AdjacencyList.Add(NodeID, TSet<int32>());
 63→	}
 64→
 65→	// 更新 ID 计数器
 66→	if (NodeID >= NextNodeID)
 67→	{
 68→		NextNodeID = NodeID + 1;
 69→	}
 70→
 71→	return NewNode;
 72→}
 73→
 74→bool ALFPWorldMapManager::RemoveNode(int32 NodeID)
 75→{
 76→	ALFPWorldMapNode** Found = NodeMap.Find(NodeID);
 77→	if (!Found) return false;
 78→
 79→	// 先移除所有关联边
 80→	if (TArray<FIntPoint>* EdgeKeys = NodeEdgeIndex.Find(NodeID))
 81→	{
 82→		// 复制一份，因为 RemoveEdge 会修改 NodeEdgeIndex
 83→		TArray<FIntPoint> KeysCopy = *EdgeKeys;
 84→		for (const FIntPoint& Key : KeysCopy)
 85→		{
 86→			if (ALFPWorldMapEdge** EdgeFound = EdgeMap.Find(Key))
 87→			{
 88→				int32 OtherID = (Key.X == NodeID) ? Key.Y : Key.X;
 89→				RemoveEdge(NodeID, OtherID);
 90→			}
 91→		}
 92→	}
 93→
 94→	// 销毁 Actor
 95→	if (*Found)
 96→	{
 97→		(*Found)->Destroy();
 98→	}
 99→
100→	NodeMap.Remove(NodeID);
101→	AdjacencyList.Remove(NodeID);
102→	NodeEdgeIndex.Remove(NodeID);
103→
104→	return true;
105→}
106→
107→ALFPWorldMapNode* ALFPWorldMapManager::GetNode(int32 NodeID) const
108→{
109→	if (const auto* Found = NodeMap.Find(NodeID))
110→	{
111→		return *Found;
112→	}
113→	return nullptr;
114→}
115→
116→TArray<ALFPWorldMapNode*> ALFPWorldMapManager::GetNeighbors(int32 NodeID) const
117→{
118→	TArray<ALFPWorldMapNode*> Result;
119→	if (const TSet<int32>* Neighbors = AdjacencyList.Find(NodeID))
120→	{
121→		for (int32 NeighborID : *Neighbors)
122→		{
123→			if (ALFPWorldMapNode* Node = GetNode(NeighborID))
124→			{
125→				Result.Add(Node);
126→			}
127→		}
128→	}
129→	return Result;
130→}
131→
132→int32 ALFPWorldMapManager::GetNextNodeID() const
133→{
134→	return NextNodeID;
135→}
136→
137→// ============== 边管理 ==============
138→
139→ALFPWorldMapEdge* ALFPWorldMapManager::AddEdge(int32 FromID, int32 ToID, int32 TurnCost)
140→{
141→	// 验证节点存在
142→	if (!NodeMap.Contains(FromID) || !NodeMap.Contains(ToID))
143→	{
144→		UE_LOG(LogTemp, Warning, TEXT("AddEdge: 节点 %d 或 %d 不存在"), FromID, ToID);
145→		return nullptr;
146→	}
147→
148→	// 不能自连
149→	if (FromID == ToID)
150→	{
151→		UE_LOG(LogTemp, Warning, TEXT("AddEdge: 不能自连节点 %d"), FromID);
152→		return nullptr;
153→	}
154→
155→	FIntPoint Key = MakeEdgeKey(FromID, ToID);
156→
157→	// 检查重复
158→	if (EdgeMap.Contains(Key))
159→	{
