	bool bNodesOk = LoadNodesFromCSV(Dir / (MapName + TEXT("_nodes.csv")));
	if (!bNodesOk) return false;

	bool bEdgesOk = LoadEdgesFromCSV(Dir / (MapName + TEXT("_edges.csv")));
