void ALFPWorldMapPlayerController::OnToggleEditorAction(const FInputActionValue& Value)
{
	if (!WorldMapEditorComponent) return;

	WorldMapEditorComponent->ToggleEditorMode();

	if (WorldMapEditorComponent->IsEditorActive())
	{
		// 创建或显示编辑器 Widget
