void ALFPWorldMapPlayerController::OnCameraPan(const FInputActionValue& Value)
{
	FVector2D PanInput = Value.Get<FVector2D>();
	CameraOffset += FVector(PanInput.X, PanInput.Y, 0) * CameraPanSpeed * GetWorld()->GetDeltaSeconds();
