void ALFPWorldMapPlayerController::OnConfirmAction(const FInputActionValue& Value)
{
	bIsDragging = false;
	if (DragTime > DragThresholdTime)
	{
		DragTime = 0.f;
		return;
	}
	DragTime = 0.f;

	// 编辑器模式优先处理
	if (WorldMapEditorComponent && WorldMapEditorComponent->IsEditorActive())
	{
