{
	TArray<FString> MapNames;
	FString Dir = GetWorldMapSaveDirectory();

	TArray<FString> FoundFiles;
	IFileManager::Get().FindFiles(FoundFiles, *(Dir / TEXT("*_nodes.csv")), true, false);

