ULFPWorldNodeDataAsset* ALFPWorldMapManager::GetNodeVisualForType(ELFPWorldNodeType NodeType) const
{
	if (const TObjectPtr<ULFPWorldNodeDataAsset>* Found = NodeVisualRegistry.Find(NodeType))
	{
		return *Found;
