}

void ALFPWorldMapPlayerController::Tick(float DeltaTime)
{
	Super::Tick(DeltaTime);

	if (bIsDragging)
	{
		DragTime += DeltaTime;
	}

	// 更新相机位置和旋转
	if (APlayerCameraManager* CameraManager = PlayerCameraManager)
	{
		// 相机位置：CameraOffset（XY 平移）+ CurrentZoom（高度）
		FVector CameraLocation = CameraOffset + FVector(0.f, 0.f, CurrentZoom);

		// 相机旋转：俯视角
		FRotator CameraRotation(CameraPitchAngle, 0.f, 0.f);

		// 平滑插值
		FVector CurrentLocation = CameraManager->GetCameraLocation();
		FRotator CurrentRotation = CameraManager->GetCameraRotation();

		CameraManager->SetManualCameraFade(0.f, FLinearColor::Black, false);
		SetControlRotation(FMath::RInterpTo(CurrentRotation, CameraRotation, DeltaTime, 5.0f));

		// 直接设置位置（或用插值）
		CameraManager->GetCameraComponent()->SetWorldLocation(
			FMath::VInterpTo(CurrentLocation, CameraLocation, DeltaTime, 5.0f)
		);
	}
}

